  ($sb$sleep_before_006$sb$, $sb$رات کو سورۂ بقرہ کی آخری دو آیات پڑھنا کافی ہے۔$sb$, $sb$قراءة الآيتين الأخيرتين من البقرة ليلًا تكفيه.$sb$),
  ($sb$sleep_before_007$sb$, $sb$رات کو سورۂ بقرہ کی آخری دو آیات پڑھنا کافی ہے۔$sb$, $sb$قراءة الآيتين الأخيرتين من البقرة ليلًا تكفيه.$sb$),
  ($sb$sleep_before_008$sb$, $sb$سونے سے پہلے شرک سے براءت کا اعلان۔$sb$, $sb$إعلان البراءة من الشرك قبل النوم.$sb$),
  ($sb$sleep_before_009$sb$, $sb$سونے سے پہلے — تیرے نام سے مرتا اور جیتا ہوں۔$sb$, $sb$تُقال قبل النوم — باسمك أموت وأحيا.$sb$),
  ($sb$sleep_before_010$sb$, $sb$اگر سونے سے پہلے یہ آخری کلام ہو تو فطرتِ اسلام پر موت۔$sb$, $sb$تموت على الفطرة إن كانت آخر كلامك قبل النوم.$sb$),
  ($sb$sleep_before_011$sb$, $sb$سونے سے پہلے اپنی جان اللہ کے سپرد کریں۔$sb$, $sb$أودِع نفسك عند الله قبل النوم.$sb$),
  ($sb$sleep_before_012$sb$, $sb$قیامت کے دن اللہ کے عذاب سے پناہ۔$sb$, $sb$استعاذة من عذاب الله يوم القيامة.$sb$),
  ($sb$sleep_before_013$sb$, $sb$حمد اس اللہ کی جس نے کھلایا، پلایا اور ٹھکانہ دیا۔$sb$, $sb$حمدٌ لله الذي أطعمنا وسقانا وآوانا.$sb$),
  ($sb$sleep_before_014$sb$, $sb$اللہ نے میری جان پیدا کی — اس کی زندگی اور موت اسی کے ہاتھ میں ہے۔$sb$, $sb$الله خلق نفسي — له محياها ومماتها.$sb$),
  ($sb$sleep_before_015$sb$, $sb$اللہ سے قرض کی ادائیگی اور فقر سے بچاؤ کا سوال۔$sb$, $sb$سؤال الله قضاء الدَّين والغنى عن الفقر.$sb$),
  ($sb$sleep_before_016$sb$, $sb$اللہ کی ذاتِ کریم اور اس کے کامل کلمات کی پناہ۔$sb$, $sb$استعاذة بوجه الله الكريم وكلماته التامات.$sb$),
  ($sb$sleep_before_017$sb$, $sb$مغفرت اور اعلیٰ مجلس میں شمولیت کا سوال۔$sb$, $sb$سؤال المغفرة واللحاق بالنديّ الأعلى.$sb$),
  ($sb$sleep_before_018$sb$, $sb$ہر حال میں اللہ کی حمد اور جہنم سے پناہ۔$sb$, $sb$الحمد لله على كل حال والاستعاذة من النار.$sb$),
  ($sb$sleep_before_019$sb$, $sb$نبی ﷺ دونوں سورتیں پڑھے بغیر نہیں سوتے تھے۔$sb$, $sb$كان النبي ﷺ لا ينام حتى يقرأ السورتين.$sb$),
  ($sb$sleep_before_020$sb$, $sb$نبی ﷺ دونوں سورتیں پڑھے بغیر نہیں سوتے تھے۔$sb$, $sb$كان النبي ﷺ لا ينام حتى يقرأ السورتين.$sb$),
  ($sb$evening_1$sb$, $sb$اللہ اور بندے کے درمیان تقسیم — ہر آیت پر اس کا جواب۔$sb$, $sb$مقسومة بين الله وعبده — لكل آية جوابها منه.$sb$),
  ($sb$evening_2$sb$, $sb$شیطان اس کے اور اس کے گھر والوں کے قریب نہیں آئے گا۔$sb$, $sb$لا يقربه الشيطان ولا أهل بيته.$sb$),
  ($sb$evening_3$sb$, $sb$اللہ کی طرف سے محافظ؛ شیطان پوری رات قریب نہیں آ سکتا۔$sb$, $sb$حافظ من الله؛ لا يقربه شيطان طوال الليل.$sb$),
  ($sb$evening_4$sb$, $sb$یہ دس آیات پڑھنے پر شیطان گھر میں داخل نہیں ہوتا۔$sb$, $sb$لا يدخل الشيطان البيت إذا قُرئت هذه الآيات العشر.$sb$),
  ($sb$evening_5$sb$, $sb$یہ دس آیات پڑھنے پر شیطان گھر میں داخل نہیں ہوتا۔$sb$, $sb$لا يدخل الشيطان البيت إذا قُرئت هذه الآيات العشر.$sb$),
  ($sb$evening_6$sb$, $sb$انہیں رات کو پڑھنا اس کے لیے کافی ہے۔$sb$, $sb$قراءتهما في ليلة تكفيه.$sb$),
  ($sb$evening_7$sb$, $sb$انہیں رات کو پڑھنا اس کے لیے کافی ہے۔$sb$, $sb$قراءتهما في ليلة تكفيه.$sb$),
  ($sb$evening_8$sb$, $sb$انہیں رات کو پڑھنا اس کے لیے کافی ہے۔$sb$, $sb$قراءتهما في ليلة تكفيه.$sb$),
  ($sb$evening_9$sb$, $sb$صبح و شام پڑھیں — ہر چیز کے مقابلے میں کافی ہوں گی۔$sb$, $sb$تُقرأ صباحًا ومساءً — تكفيك من كل شيء.$sb$),
  ($sb$evening_10$sb$, $sb$صبح و شام پڑھیں — ہر چیز کے مقابلے میں کافی ہوں گی۔$sb$, $sb$تُقرأ صباحًا ومساءً — تكفيك من كل شيء.$sb$),
  ($sb$evening_11$sb$, $sb$صبح و شام پڑھیں — ہر چیز کے مقابلے میں کافی ہوں گی۔$sb$, $sb$تُقرأ صباحًا ومساءً — تكفيك من كل شيء.$sb$),
  ($sb$evening_12$sb$, $sb$بادشاہی، تمام حمد اور تمام معاملات اللہ ہی کے ہیں۔$sb$, $sb$الملك والحمد والأمر كله لله.$sb$),
  ($sb$evening_13$sb$, $sb$اسلام، اخلاص اور ملتِ ابراہیم کا اقرار۔$sb$, $sb$إقرار بالإسلام والإخلاص وملة إبراهيم.$sb$),
  ($sb$evening_14$sb$, $sb$اللہ ہی سے ہم جیتے اور مرتے ہیں، اسی کی طرف لوٹنا ہے۔$sb$, $sb$بالله نحيا ونموت وإليه المصير.$sb$),
  ($sb$evening_15$sb$, $sb$صبح و شام اللہ کی نعمت، عافیت اور پردہ پوشی۔$sb$, $sb$نعمة الله وعافيته وستره صباحًا ومساءً.$sb$),
  ($sb$evening_16$sb$, $sb$دن بھر کے شکر کا فریضہ ادا کر دیتی ہے۔$sb$, $sb$تؤدّي واجب شكر الله عن اليوم.$sb$),
  ($sb$evening_17$sb$, $sb$اس حمد کو اللہ خود لکھتا اور اس کا اجر دیتا ہے۔$sb$, $sb$يتولى الله بنفسه كتابة هذا الحمد ومجازاته.$sb$),
  ($sb$evening_18$sb$, $sb$اللہ کا وعدہ ہے کہ قیامت کے دن تمہیں راضی کرے گا۔$sb$, $sb$وعدُ الله أن يُرضيك يوم القيامة.$sb$),
  ($sb$evening_19$sb$, $sb$دین، اہل و عیال اور مال کے لیے عافیت اور حفاظت۔$sb$, $sb$عافية وحفظ في الدين والأهل والمال.$sb$),
  ($sb$evening_20$sb$, $sb$صبح سے کہی گئی ہر بات سے وزنی۔$sb$, $sb$تفوق وزنًا كل ما قيل منذ الصباح.$sb$),
  ($sb$evening_21$sb$, $sb$صبح و شام تین بار کہنے پر کوئی چیز نقصان نہیں پہنچاتی۔$sb$, $sb$لا يضرك شيء إذا قلتها ثلاث مرات صباحًا ومساءً.$sb$),
  ($sb$evening_22$sb$, $sb$چھوٹے اور بڑے دونوں شرک سے نجات دیتی ہے۔$sb$, $sb$تُخلّصك من صغير الشرك وكبيره.$sb$),
  ($sb$evening_23$sb$, $sb$اس جگہ سے جانے تک کوئی چیز نقصان نہیں پہنچاتی۔$sb$, $sb$لا يضرك شيء حتى ترحل من ذلك المكان.$sb$),
  ($sb$evening_24$sb$, $sb$نفس، شیطان اور شرک کے شر سے پناہ۔$sb$, $sb$استعاذة من شر النفس والشيطان وشركه.$sb$),
  ($sb$evening_25$sb$, $sb$نبی ﷺ نے فاطمہ کو صبح و شام کے لیے سکھائی۔$sb$, $sb$علّمها النبي ﷺ لفاطمة صباحًا ومساءً.$sb$),
  ($sb$evening_26$sb$, $sb$رات کو یقین کے ساتھ کہنے پر — اہلِ جنت میں سے ہوں گے۔$sb$, $sb$من قالها ليلًا موقنًا بها — كان من أهل الجنة.$sb$),
  ($sb$evening_27$sb$, $sb$اس دن یا رات کے گناہ اللہ معاف کر دیتا ہے۔$sb$, $sb$يغفر الله ما أصاب من ذنب في يومه أو ليلته.$sb$),
  ($sb$evening_28$sb$, $sb$صبح و شام جسم، سماعت اور بینائی کی حفاظت۔$sb$, $sb$حفظ للبدن والسمع والبصر صباحًا ومساءً.$sb$),
  ($sb$evening_29$sb$, $sb$جو کچھ تمہیں فکرمند کرے، اللہ اس کے لیے کافی ہو گا۔$sb$, $sb$يكفيك الله ما أهمّك.$sb$),
  ($sb$evening_30$sb$, $sb$دس غلام آزاد کرنے کا اجر اور شیطان سے ڈھال۔$sb$, $sb$أجر عتق عشر رقاب وحرز من الشيطان.$sb$),
  ($sb$evening_31$sb$, $sb$گناہ معاف، چاہے سمندر کی جھاگ جتنے ہوں۔$sb$, $sb$تُغفر الذنوب ولو كانت مثل زبد البحر.$sb$),
  ($sb$evening_32$sb$, $sb$قیامت کے دن نبی ﷺ کی شفاعت تم تک پہنچتی ہے۔$sb$, $sb$تنالك شفاعة النبي ﷺ يوم القيامة.$sb$),
  ($sb$family_dua_spouse$sb$, $sb$اللہ سے سوال کہ ازدواج میں دل جوڑ دے جیسے مومنوں کے دل جوڑے۔$sb$, $sb$سؤال الله أن يؤلّف بين قلوب الزوجين كما ألّف بين المؤمنين.$sb$),
  ($sb$family_new_marriage$sb$, $sb$نئے شادی شدہ جوڑے کے لیے مسنون مبارکباد۔$sb$, $sb$التهنئة المسنونة للعروسين.$sb$),
  ($sb$food_bismillah$sb$, $sb$ہر کھانے کے آغاز پر اللہ کا نام لیں۔$sb$, $sb$اذكر اسم الله في أول كل طعام.$sb$),
  ($sb$food_after$sb$, $sb$حمد اس اللہ کی جس نے کھلایا، پلایا اور مسلمان بنایا۔$sb$, $sb$الحمد لله الذي أطعمنا وسقانا وجعلنا مسلمين.$sb$),
  ($sb$bocp_146$sb$, $sb$دن کے آغاز میں درستی، فلاح اور کامیابی کا سوال۔$sb$, $sb$سؤال الله صلاح اليوم وفلاحه ونجاحه.$sb$),
  ($sb$bocp_147$sb$, $sb$اللہ کی وحدانیت کی گواہی اور مغفرت کا سوال۔$sb$, $sb$شهادة بوحدانية الله وسؤال المغفرة.$sb$),
  ($sb$bocp_148$sb$, $sb$نکمے بڑھاپے کی طرف لوٹائے جانے سے پناہ۔$sb$, $sb$استعاذة من الرد إلى أرذل العمر.$sb$),
  ($sb$bocp_149$sb$, $sb$بہترین اعمال کی ہدایت اور بدترین سے حفاظت۔$sb$, $sb$هداية لأحسن الأعمال وصرف لسيئها.$sb$),
  ($sb$bocp_150$sb$, $sb$دین، گھر اور رزق کی درستی کا سوال۔$sb$, $sb$سؤال الله إصلاح الدين والدار والرزق.$sb$),
  ($sb$bocp_151$sb$, $sb$سنگدلی، ریاکاری اور لاعلاج بیماریوں سے پناہ۔$sb$, $sb$استعاذة من القسوة والرياء وسيئ الأسقام.$sb$),
  ($sb$bocp_152$sb$, $sb$تباہی، ڈوبنے، جلنے اور زہر سے مرنے سے پناہ۔$sb$, $sb$استعاذة من الهدم والغرق والحرق والموت لديغًا.$sb$),
  ($sb$bocp_153$sb$, $sb$ثابت قدمی، شکرگزاری اور قلبِ سلیم کا سوال۔$sb$, $sb$سؤال الثبات والشكر والقلب السليم.$sb$),
  ($sb$bocp_154$sb$, $sb$نیکی کرنے، برائی چھوڑنے اور مسکینوں سے محبت کا سوال۔$sb$, $sb$سؤال فعل الخيرات وترك المنكرات وحب المساكين.$sb$),
  ($sb$bocp_155$sb$, $sb$اللہ، اس کے فرشتوں، انبیاء اور مخلوق کی محبت کا سوال۔$sb$, $sb$سؤال محبة الله وملائكته وأنبيائه وجميع خلقه.$sb$),
  ($sb$bocp_156$sb$, $sb$اللہ کی محبت ہر محبت سے بڑھ کر — حتیٰ کہ پیاس میں ٹھنڈے پانی سے بھی۔$sb$, $sb$سؤال أن يكون حب الله أحب من كل شيء — حتى الماء البارد على الظمأ.$sb$),
  ($sb$bocp_157$sb$, $sb$زندگی، اعمال اور دنوں کے بہترین انجام کا سوال۔$sb$, $sb$سؤال خير العمر آخره وخير العمل خواتمه.$sb$),
  ($sb$bocp_158$sb$, $sb$پاکیزہ زندگی، پرسکون موت اور باعزت واپسی کا سوال۔$sb$, $sb$سؤال عيشة نقية وميتة سوية ومردّ غير مخزٍ.$sb$),
  ($sb$bocp_159$sb$, $sb$صبر، شکر اور لوگوں کے سامنے عاجزی کا سوال۔$sb$, $sb$سؤال الصبر والشكر والتواضع.$sb$),
  ($sb$bocp_160$sb$, $sb$بہترین دعا اور جنت کے بلند ترین درجات کا سوال۔$sb$, $sb$سؤال خير الدعاء والدرجات العلى من الجنة.$sb$),
  ($sb$bocp_161$sb$, $sb$خیر کے دروازے کھلنے اور اعلیٰ جنت کا سوال۔$sb$, $sb$سؤال فواتح الخير والدرجات العلى من الجنة.$sb$),
  ($sb$bocp_162$sb$, $sb$ہر خیر — ظاہر و پوشیدہ — اور اعلیٰ جنت کا سوال۔$sb$, $sb$سؤال خير ما بطن وما ظهر والدرجات العلى من الجنة.$sb$),
  ($sb$bocp_163$sb$, $sb$ذکر کی بلندی، دل کی پاکیزگی اور گناہوں کی مغفرت کا سوال۔$sb$, $sb$سؤال رفع الذكر وتطهير القلب ومغفرة الذنب.$sb$),
  ($sb$bocp_164$sb$, $sb$سماعت، بینائی، روح، اہل و عیال اور عمل میں برکت کا سوال۔$sb$, $sb$سؤال البركة في السمع والبصر والروح والأهل والعمل.$sb$),
  ($sb$bocp_165$sb$, $sb$مغفرت، رحمت، جنت اور جہنم سے نجات کا سوال۔$sb$, $sb$سؤال المغفرة والرحمة والجنة والنجاة من النار.$sb$),
  ($sb$bocp_166$sb$, $sb$ہر گناہ معاف، ہر قرض ادا اور ہر فکر دور ہونے کا سوال۔$sb$, $sb$سؤال ألا يبقى ذنب إلا غُفر ولا دين إلا قُضي ولا هم إلا فُرّج.$sb$),
  ($sb$bocp_167$sb$, $sb$ایسی رحمت کا سوال جو دل کو ہدایت دے اور تمام معاملات سنوار دے۔$sb$, $sb$سؤال رحمة تهدي القلب وتجمع الأمر.$sb$),
  ($sb$bocp_168$sb$, $sb$سچے ایمان، یقین اور دونوں جہانوں میں رحمت کا سوال۔$sb$, $sb$سؤال إيمان صادق ويقين ورحمة في الدارين.$sb$),
  ($sb$bocp_169$sb$, $sb$قیامت کے دن کامیابی اور شہداء کی رفاقت کا سوال۔$sb$, $sb$سؤال الفوز يوم القضاء ومنازل الشهداء.$sb$),
  ($sb$bocp_170$sb$, $sb$دلوں کے شافی اللہ سے جہنم اور قبر سے پناہ کا سوال۔$sb$, $sb$سؤال الله — شافي الصدور — الإجارة من النار والقبر.$sb$),
  ($sb$bocp_171$sb$, $sb$اس خیر کا سوال جہاں علم اور عمل نہیں پہنچ سکتے۔$sb$, $sb$سؤال الله ما قصر عنه العلم والعمل.$sb$),
  ($sb$bocp_172$sb$, $sb$یومِ وعید کے امن اور دائمی جنت کا سوال۔$sb$, $sb$سؤال الأمن يوم الوعيد والجنة يوم الخلود.$sb$),
  ($sb$bocp_173$sb$, $sb$پاک ہے وہ جس کا علم ہر چیز کا احاطہ کیے ہوئے ہے۔$sb$, $sb$سبحان من أحصى كل شيء علمه.$sb$),
  ($sb$bocp_174$sb$, $sb$دین اور دنیا میں معافی اور دائمی عافیت کا سوال۔$sb$, $sb$سؤال العفو والمعافاة الدائمة في الدين والدنيا.$sb$),
  ($sb$bocp_175$sb$, $sb$ایمان کے ساتھ صحت، کامیابی، رحمت اور مغفرت کا سوال۔$sb$, $sb$سؤال صحة في إيمان ونجاح ورحمة ومغفرة.$sb$),
  ($sb$bocp_176$sb$, $sb$صحت، عفت، حسنِ اخلاق اور تقدیر پر رضا کا سوال۔$sb$, $sb$سؤال الصحة والعفة وحسن الخلق والرضا بالقدر.$sb$),
  ($sb$bocp_177$sb$, $sb$ہدایت یافتہ اور ہدایت دینے والوں میں شامل ہونے کا سوال۔$sb$, $sb$سؤال أن نكون هادين مهديين.$sb$),
  ($sb$bocp_178$sb$, $sb$نفس اور تمام مخلوقات کے شر سے پناہ۔$sb$, $sb$استعاذة من شر النفس وكل دابة.$sb$),
  ($sb$bocp_179$sb$, $sb$ایسی رحمت کا سوال جو غیر کی رحمت سے بے نیاز کر دے۔$sb$, $sb$سؤال رحمة تُغني عن رحمة من سواه.$sb$),
  ($sb$bocp_180$sb$, $sb$صبح کے وقت ہر شر اور انسانوں و جنوں کے شیاطین سے پناہ۔$sb$, $sb$استعاذة صباحية من كل شر ومن شياطين الإنس والجن.$sb$),
  ($sb$bocp_181$sb$, $sb$موسیٰ، عیسیٰ اور ابراہیم کی مانگی ہوئی ہر شر سے پناہ۔$sb$, $sb$الاستعاذة التي استعاذ بها موسى وعيسى وإبراهيم من كل شر.$sb$),
  ($sb$bocp_182$sb$, $sb$اللہ کے پاس موجود بہترین خیر اور اس کی برکتوں کا سوال۔$sb$, $sb$سؤال خير ما عند الله وبركاته.$sb$),
  ($sb$bocp_183$sb$, $sb$اقرار کہ تمام حمد، بادشاہی اور خیر اللہ ہی کے ہیں۔$sb$, $sb$إقرار بأن الحمد كله والملك كله والخير كله لله.$sb$),
  ($sb$bocp_184$sb$, $sb$پچھلے گناہوں کی معافی اور باقی زندگی کی حفاظت کا سوال۔$sb$, $sb$سؤال غفران ما مضى والعصمة فيما بقي من العمر.$sb$),
  ($sb$bocp_185$sb$, $sb$اللہ سے کمزور بندے کو اپنی رضا میں قوت دینے کا سوال۔$sb$, $sb$سؤال الله أن يقوّي العبد الضعيف في رضاه.$sb$),
  ($sb$bocp_186$sb$, $sb$کمزور کو قوت، عاجز کو عزت اور فقیر کو غنا کا سوال۔$sb$, $sb$سؤال القوة للضعيف والعز للذليل والغنى للفقير.$sb$),
  ($sb$bocp_187$sb$, $sb$اللہ سے اس کے رسولوں کو جھٹلانے والوں کی شکست کا سوال۔$sb$, $sb$سؤال الله هزيمة من يكذّبون رسله.$sb$),
  ($sb$bocp_188$sb$, $sb$طاعون، وبا اور جان و اہل کی آفت سے پناہ۔$sb$, $sb$استعاذة من الطاعون والوباء والبلاء في النفس والأهل.$sb$),
  ($sb$bocp_189$sb$, $sb$اچانک موت، شدید بیماری اور دشمنوں کی خوشی سے پناہ۔$sb$, $sb$استعاذة من موت الفجأة وشدة الحمى وشماتة الأعداء.$sb$),
  ($sb$bocp_190$sb$, $sb$جلد کشادگی اور لمبی، عافیت والی زندگی کا سوال۔$sb$, $sb$سؤال تعجيل الفرج وعمر طويل في عافية.$sb$),
  ($sb$bocp_191$sb$, $sb$شیطانی وسوسوں سے اللہ کے کامل کلمات کی پناہ۔$sb$, $sb$استعاذة بكلمات الله التامات من همزات الشياطين.$sb$),
  ($sb$bocp_192$sb$, $sb$اقرار کہ گناہ اور قرض دور کرنے والا صرف اللہ ہے۔$sb$, $sb$إقرار بأن الله وحده كاشف المأثم والمغرم.$sb$),
  ($sb$bocp_193$sb$, $sb$طائف کے دن نبی ﷺ کی فریاد — شکوہ صرف اللہ سے۔$sb$, $sb$شكوى النبي ﷺ يوم الطائف — لا يشكو إلا إلى الله.$sb$),
  ($sb$bocp_194$sb$, $sb$نفع بخش علم اور سکھائے گئے علم سے نفع کا سوال۔$sb$, $sb$سؤال العلم النافع والانتفاع بما عُلِّم.$sb$),
  ($sb$bocp_195$sb$, $sb$اللہ سے ویسے علم و فہم کا سوال جیسا ابراہیم اور سلیمان کو دیا۔$sb$, $sb$سؤال الله التعليم كما علّم إبراهيم وفهّم سليمان.$sb$),
  ($sb$bocp_196$sb$, $sb$ہر پریشانی سے راحت، ہر تنگی سے راستہ اور ہر آزمائش سے حفاظت کی دعا۔$sb$, $sb$طلب الفرج من كل هم والمخرج من كل ضيق والعافية من كل بلاء.$sb$),
  ($sb$bocp_197$sb$, $sb$مسلمانوں کے خلاف برائی چاہنے والوں کا شر ان ہی پر لوٹانے کا سوال۔$sb$, $sb$سؤال الله أن يشغل من أراد المسلمين بسوء في نفسه.$sb$),
  ($sb$bocp_198$sb$, $sb$دشمنوں کو روکنے اور ان کے شر سے پناہ کا سوال۔$sb$, $sb$سؤال دفع الأعداء والاستعاذة من شرورهم.$sb$),
  ($sb$bocp_199$sb$, $sb$اپنے، والدین اور تمام مومنوں کے لیے مغفرت کا سوال۔$sb$, $sb$سؤال المغفرة للنفس والوالدين وجميع المؤمنين.$sb$),
  ($sb$bocp_200$sb$, $sb$دل، اعمال، زبان اور آنکھوں کی پاکیزگی کا سوال۔$sb$, $sb$سؤال تطهير القلب والعمل واللسان والعين.$sb$),
  ($sb$bocp_201$sb$, $sb$ایسے نفس کا سوال جو اللہ سے ملاقات پر مطمئن اور اس کے فیصلے پر راضی ہو۔$sb$, $sb$سؤال نفس مطمئنة بلقاء الله راضية بقضائه.$sb$),
  ($sb$bocp_202$sb$, $sb$اللہ سے معذرت کی قبولیت کا سوال — وہ ہر ضرورت جانتا ہے۔$sb$, $sb$سؤال قبول المعذرة — وهو يعلم حاجتك.$sb$),
  ($sb$bocp_203$sb$, $sb$ایمان اور اللہ کی تقدیر پر یقین کا سوال۔$sb$, $sb$سؤال الإيمان واليقين بقضاء الله.$sb$),
  ($sb$bocp_204$sb$, $sb$ہدایت دینے والا ایمان، رہنما نور اور حلال رزق کا سوال۔$sb$, $sb$سؤال إيمان يُهتدى به ونور يُقتدى به ورزق حلال.$sb$),
  ($sb$bocp_205$sb$, $sb$پورے دل سے اللہ کی محبت اور پوری کوشش سے اس کی رضا کا سوال۔$sb$, $sb$سؤال محبة الله بالقلب كله وإرضائه بالجهد كله.$sb$),
  ($sb$bocp_206$sb$, $sb$جو روک لیا گیا اسے اللہ کی پسندیدہ چیزوں کی قوت بنانے کا سوال۔$sb$, $sb$سؤال أن يجعل ما زُوي عنه قوة فيما يحب الله.$sb$),
  ($sb$bocp_207$sb$, $sb$تسبیح، حمد اور کبریائی — عرش کے وزن کے برابر۔$sb$, $sb$تسبيح وتحميد وتكبير — ملء الميزان وزنة العرش.$sb$),
  ($sb$bocp_208$sb$, $sb$ہر چیز جاننے والے اللہ سے ہر فکر سے کشادگی کا سوال۔$sb$, $sb$سؤال الله — العالم بكل شيء — الفرج من كل هم.$sb$),
  ($sb$bocp_209$sb$, $sb$اللہ کی معافی بندے کو ہر چیز مانگنے کی جرأت دیتی ہے۔$sb$, $sb$عفو الله يجرّئ العبد على سؤاله كل شيء.$sb$),
  ($sb$bocp_210$sb$, $sb$اللہ سے بندوں کی محبت اور برے لوگوں سے کفایت کا سوال۔$sb$, $sb$سؤال الله أن يحنّن عليك عباده ويكفيك شرارهم.$sb$),
  ($sb$bocp_211$sb$, $sb$اللہ کی عزت، قدرت اور سلطنت کے ذریعے ہر شر سے پناہ۔$sb$, $sb$استعاذة بعزة الله وقدرته وسلطانه من كل شر.$sb$),
  ($sb$bocp_212$sb$, $sb$شکرگزار، آزمائش میں ثابت قدم اور نیکوں کا مددگار بننے کا سوال۔$sb$, $sb$سؤال الشكر والصبر على البلاء ونصرة الأولياء.$sb$),
  ($sb$bocp_213$sb$, $sb$سوال کہ اللہ ہمارے گناہ کی وجہ سے اپنی خیر نہ روکے۔$sb$, $sb$سؤال ألا يحرمنا الله خيره بسوء ما عندنا.$sb$),
  ($sb$bocp_214$sb$, $sb$پرسکون زندگی، وافر رزق اور نیک اعمال کا سوال۔$sb$, $sb$سؤال عيش قارّ ورزق دارّ وعمل بارّ.$sb$),
  ($sb$bocp_215$sb$, $sb$اللہ کی محتاجی سے غنا کا سوال، اس سے بے نیازی سے فقر نہیں۔$sb$, $sb$سؤال الغنى بالافتقار إلى الله لا الفقر بالاستغناء عنه.$sb$),
  ($sb$bocp_216$sb$, $sb$عیبوں کی پردہ پوشی، خوف سے امان اور کرب میں تخفیف کا سوال۔$sb$, $sb$سؤال ستر العورة وأمن الروعة وتخفيف اللوعة.$sb$),
  ($sb$bocp_217$sb$, $sb$رحمت کے دروازے کھلنے اور کرم کی بارش کا سوال۔$sb$, $sb$سؤال فتح أبواب الرحمة واستمطار السماحة.$sb$),
  ($sb$bocp_218$sb$, $sb$سلامتی اور آزمائشوں کے حوالے نہ کیے جانے کا سوال۔$sb$, $sb$سؤال السلامة وألا يُسلمنا الله للفتن.$sb$),
  ($sb$bocp_219$sb$, $sb$اللہ کی ضمانت، امان اور احسان میں رہنے کا سوال۔$sb$, $sb$سؤال أن نكون في ضمان الله وأمانه وإحسانه.$sb$),
  ($sb$bocp_220$sb$, $sb$ہر گناہ کی معافی اور ہر کرب سے نجات کا سوال۔$sb$, $sb$سؤال مغفرة كل ذنب وتفريج كل كرب.$sb$),
  ($sb$bocp_221$sb$, $sb$موت، قبر، پل صراط اور قیامت کے دن مدد کا سوال۔$sb$, $sb$سؤال العون عند الموت والقبر والصراط ويوم القيامة.$sb$),
  ($sb$bocp_222$sb$, $sb$خوبصورت زندگی، موت پر رحمت اور غیر متزلزل ایمان کا سوال۔$sb$, $sb$سؤال جمال العيش والرحمة عند الموت وثبات الإيمان.$sb$),
  ($sb$bocp_223$sb$, $sb$نیکی میں ثابت قدمی اور قبر میں راحت کا سوال۔$sb$, $sb$سؤال الثبات في الخيرات وتنفيس كربة القبر.$sb$),
  ($sb$bocp_224$sb$, $sb$امید نہ ٹوٹنے اور توبہ کرنے والے دل کا سوال۔$sb$, $sb$سؤال ألا ينقطع الرجاء وأن يُرزق قلبًا توابًا.$sb$),
  ($sb$bocp_225$sb$, $sb$سب سے درست معاملات کی طرف ہدایت کا سوال۔$sb$, $sb$سؤال الهداية لأرشد الأمور.$sb$),
  ($sb$bocp_226$sb$, $sb$اللہ کی ثنا — گناہ معاف کرنے والا، توبہ قبول کرنے والا۔$sb$, $sb$ثناء على الله — غافر الذنب وقابل التوب.$sb$),
  ($sb$bocp_227$sb$, $sb$ٹوٹے عہدوں اور دوبارہ گناہوں کی طرف لوٹنے پر مغفرت کا سوال۔$sb$, $sb$استغفار من نقض العهود والعودة إلى الذنوب.$sb$),
  ($sb$bocp_228$sb$, $sb$ایسے فہم کا سوال جس سے صدیقین کے مقام تک پہنچا جائے۔$sb$, $sb$سؤال فهم يُبلّغ منازل الصديقين.$sb$),
  ($sb$bocp_229$sb$, $sb$ان لوگوں میں شمولیت کا سوال جن کے دل تقویٰ کی بلندیوں میں ٹھہرے ہیں۔$sb$, $sb$سؤال أن نكون ممن حطّت قلوبهم في غاية التقى.$sb$),
  ($sb$bocp_230$sb$, $sb$صبر کا دروازہ کھولنے اور خواہش کا پل پار کرنے والوں میں شمولیت کا سوال۔$sb$, $sb$سؤال أن نكون ممن فتحوا باب الصبر وعبروا جسر الهوى.$sb$),
  ($sb$bocp_231$sb$, $sb$اخلاص اور یقین کی راہ پانے والوں میں شمولیت کا سوال۔$sb$, $sb$سؤال أن نكون ممن سلكوا سبيل الإخلاص واليقين.$sb$),
  ($sb$bocp_232$sb$, $sb$برائی کی طرف مائل نفس کی معافی اور مکمل درگزر کا سوال۔$sb$, $sb$سؤال مغفرة النفس الأمّارة بالسوء والعفو التام.$sb$),
  ($sb$bocp_233$sb$, $sb$اللہ سے ایسے ڈرنے کا سوال جیسے اسے دیکھ رہے ہوں، اور ظالم پر نصرت۔$sb$, $sb$سؤال خشية الله كأنك تراه والنصر على من ظلمك.$sb$),
  ($sb$bocp_234$sb$, $sb$اپنی جان، اہل، مال اور اولاد اللہ کے سپرد کریں۔$sb$, $sb$استودع الله نفسك وأهلك ومالك وولدك.$sb$),
  ($sb$bocp_235$sb$, $sb$ایمان کے ذریعے حفاظت اور ایمان کی حفاظت کا سوال۔$sb$, $sb$سؤال الحفظ بالإيمان وحفظ الإيمان لنا.$sb$),
  ($sb$bocp_236$sb$, $sb$اللہ کی رحمت اور اس کے فضل سے محروم نہ ہونے کا سوال۔$sb$, $sb$سؤال رحمة الله وألا يُسلب فضله.$sb$),
  ($sb$bocp_237$sb$, $sb$سفر کی مشقت اور واپسی پر برے منظر سے پناہ۔$sb$, $sb$استعاذة من وعثاء السفر وسوء المنقلب.$sb$),
  ($sb$bocp_238$sb$, $sb$اللہ کی نازل کردہ ہر خیر میں حصہ بڑھنے کا سوال۔$sb$, $sb$سؤال توفير الحظ من كل خير ينزله الله.$sb$),
  ($sb$bocp_239$sb$, $sb$ہر سازش کے رد اور اللہ کے قرب کا سوال۔$sb$, $sb$سؤال رد كل كيد ونيل القرب من الله.$sb$),
  ($sb$bocp_240$sb$, $sb$مشکل میں اللہ کی دستگیری اور ہر جانب سے حفاظت کا سوال۔$sb$, $sb$سؤال الأخذ باليد في المضائق والكفاية من جميع الجهات.$sb$),
  ($sb$bocp_241$sb$, $sb$پلک جھپکنے کے برابر بھی اپنے نفس کے حوالے نہ کیے جانے کا سوال۔$sb$, $sb$سؤال ألا يكِلنا الله إلى أنفسنا طرفة عين.$sb$),
  ($sb$bocp_242$sb$, $sb$اللہ کی عزت اور اپنی عاجزی کے واسطے رحمت کا سوال۔$sb$, $sb$سؤال الرحمة بعز الله وذل العبد.$sb$),
  ($sb$bocp_243$sb$, $sb$زندگی میں عافیت اور انجام پر مغفرت کا سوال۔$sb$, $sb$سؤال العافية في الحياة والمغفرة في الختام.$sb$),
  ($sb$bocp_244$sb$, $sb$دنیا سے اتنا حصہ مانگنا جو اس کے فتنوں سے بچائے۔$sb$, $sb$سؤال من الدنيا ما يقي فتنتها.$sb$),
  ($sb$bocp_245$sb$, $sb$رزق پر قناعت اور ہر کھوئی چیز کے اچھے بدل کا سوال۔$sb$, $sb$سؤال القناعة بالرزق والخلف الحسن لكل غائبة.$sb$),
  ($sb$gatherings_opening$sb$, $sb$مجلسوں میں اللہ کا ذکر قیامت کے دن حسرت سے بچاتا ہے۔$sb$, $sb$ذكر الله في المجالس يقي الحسرة يوم القيامة.$sb$),
  ($sb$gatherings_closing$sb$, $sb$مجلس سے اٹھنے سے پہلے — لغو باتوں کا کفارہ۔$sb$, $sb$تُقال قبل مغادرة المجلس — كفارة اللغو.$sb$),
  ($sb$subhanallah$sb$, $sb$گناہ مٹ جاتے ہیں، چاہے سمندر کی جھاگ جتنے ہوں۔$sb$, $sb$تُمحى الذنوب ولو كانت مثل زبد البحر.$sb$),
  ($sb$alhamdulillah$sb$, $sb$نیکیوں کا میزان بھر دیتی ہے۔$sb$, $sb$تملأ ميزان الحسنات.$sb$),
  ($sb$allahu_akbar$sb$, $sb$نبی ﷺ کو ہر اس چیز سے زیادہ محبوب جس پر سورج طلوع ہوتا ہے۔$sb$, $sb$أحب إلى النبي ﷺ مما طلعت عليه الشمس.$sb$),
  ($sb$la_ilaha_illallah$sb$, $sb$دس غلام آزاد کرنے کا اجر؛ دن بھر شیطان سے ڈھال۔$sb$, $sb$أجر عتق عشر رقاب وحرز من الشيطان طوال اليوم.$sb$),
  ($sb$la_hawla$sb$, $sb$جنت کے خزانوں میں سے ایک خزانہ۔$sb$, $sb$كنز من كنوز الجنة.$sb$),
  ($sb$subhanallahi_wabihamdih$sb$, $sb$صبح و شام 100 بار — قیامت کے دن اس سے بہتر کوئی نہیں لائے گا۔$sb$, $sb$تُقال 100 مرة صباحًا ومساءً — لا يأتي أحد يوم القيامة بأفضل منها.$sb$),
  ($sb$subhanallahi_al_azeem$sb$, $sb$زبان پر ہلکے، میزان میں بھاری، رحمٰن کو محبوب۔$sb$, $sb$خفيفتان على اللسان ثقيلتان في الميزان حبيبتان إلى الرحمن.$sb$),
  ($sb$hajj_talbiyah$sb$, $sb$احرام سے کہی جاتی ہے — ہر پتھر اور درخت ساتھ شامل ہوتا ہے۔$sb$, $sb$تُقال من الإحرام — يلبّي معه كل حجر وشجر.$sb$),
  ($sb$hajj_tawaf$sb$, $sb$اللہ کو سب سے محبوب چار کلمات۔$sb$, $sb$الكلمات الأربع الأحب إلى الله.$sb$),
  ($sb$bocp_254$sb$, $sb$احرام سے جمرہ کی رمی تک بلند آواز سے پڑھی جاتی ہے۔$sb$, $sb$تُرفع بها الأصوات من الإحرام حتى رمي الجمرة.$sb$),
  ($sb$bocp_255$sb$, $sb$مسجد میں داخل ہوتے وقت، پہلے دایاں قدم۔$sb$, $sb$تُقال عند دخول المسجد بالقدم اليمنى.$sb$),
  ($sb$bocp_256$sb$, $sb$ساتوں چکروں میں حجرِ اسود کے سامنے کہی جاتی ہے۔$sb$, $sb$تُقال عند محاذاة الحجر الأسود في كل شوط من الأشواط السبعة.$sb$),
  ($sb$bocp_257$sb$, $sb$دنیا اور آخرت کی بھلائی اور جہنم سے پناہ کا سوال۔$sb$, $sb$سؤال حسنة الدنيا والآخرة والوقاية من النار.$sb$),
  ($sb$bocp_258$sb$, $sb$طواف کے بعد، مقامِ ابراہیم کے پیچھے نماز سے پہلے پڑھی جاتی ہے۔$sb$, $sb$تُقرأ بعد الطواف قبل الصلاة خلف مقام إبراهيم.$sb$),
  ($sb$bocp_259$sb$, $sb$صفا اور مروہ پر پڑھی جاتی ہے، درمیان میں ذاتی دعا۔$sb$, $sb$تُقرأ على الصفا والمروة مع الدعاء الشخصي بينهما.$sb$),
  ($sb$bocp_260$sb$, $sb$بہترین دعا — عرفہ کے دن تمام انبیاء نے کہی۔$sb$, $sb$خير الدعاء — قاله الأنبياء جميعًا يوم عرفة.$sb$),
  ($sb$bocp_261$sb$, $sb$فجر کے بعد طلوعِ آفتاب تک — قبلہ رخ، ہاتھ اٹھا کر دعا۔$sb$, $sb$بعد الفجر حتى الشروق — استقبل القبلة وارفع يديك وادعُ.$sb$),
  ($sb$bocp_262$sb$, $sb$ہر ستون پر ساتوں کنکریوں کے ساتھ کہی جاتی ہے۔$sb$, $sb$تُقال مع كل حصاة من الحصيات السبع عند كل جمرة.$sb$),
  ($sb$bocp_263$sb$, $sb$زمزم جس نیت سے پیا جائے اسی کے لیے ہے — اپنی حاجتوں کی دعا کریں۔$sb$, $sb$ماء زمزم لما شُرب له — فادعُ بحاجاتك.$sb$),
  ($sb$home_entering$sb$, $sb$داخل ہوتے وقت کہنے پر شیطان کو رات گزارنے کی جگہ نہیں ملتی۔$sb$, $sb$لا يجد الشيطان مبيتًا إذا قيلت عند الدخول.$sb$),
  ($sb$home_protection$sb$, $sb$اس جگہ سے جانے تک کوئی چیز نقصان نہیں پہنچاتی۔$sb$, $sb$لا يضرك شيء حتى ترحل من ذلك المكان.$sb$),
  ($sb$iman_refuge$sb$, $sb$جب دل میں وسوسے یا شکوک آئیں تو کہی جاتی ہے۔$sb$, $sb$تُقال عند ورود الوساوس أو الشكوك على القلب.$sb$),
  ($sb$iman_falaq_nas$sb$, $sb$صبح و شام تین بار — ہر نقصان کے مقابلے میں کافی۔$sb$, $sb$تُقرأ ثلاثًا صباحًا ومساءً — تكفي من كل شيء.$sb$),
  ($sb$iman_tawakkul$sb$, $sb$گھر سے نکلتے وقت — تمہیں ہدایت، دفاع اور حفاظت ملتی ہے۔$sb$, $sb$تُقال عند الخروج — هُديت وكُفيت ووُقيت.$sb$),
  ($sb$astaghfirullah$sb$, $sb$اللہ پریشانی دور کرتا اور وہاں سے رزق دیتا ہے جہاں گمان نہ ہو۔$sb$, $sb$يفرّج الله الكرب ويرزق من حيث لا تحتسب.$sb$),
  ($sb$istighfar_extended$sb$, $sb$نبی ﷺ دن میں ستر سے زیادہ بار استغفار کرتے تھے۔$sb$, $sb$كان النبي ﷺ يستغفر في اليوم أكثر من سبعين مرة.$sb$),
  ($sb$sayyid_istighfar$sb$, $sb$یقین کے ساتھ کہنے پر — اگر اسی دن موت آئے تو اہلِ جنت میں سے ہوں گے۔$sb$, $sb$من قالها موقنًا بها فمات من يومه — كان من أهل الجنة.$sb$),
  ($sb$istikharah_dua$sb$, $sb$دو رکعت کے بعد — اللہ بہتر کو آسان کر دیتا ہے۔$sb$, $sb$تُدعى بعد ركعتين — ييسّر الله ما هو خير.$sb$),
  ($sb$masjid_entering$sb$, $sb$مسجد میں داخل ہوتے وقت اللہ رحمت کے دروازے کھولتا ہے۔$sb$, $sb$يفتح الله أبواب الرحمة عند دخول المسجد.$sb$),
  ($sb$masjid_exiting$sb$, $sb$مسجد سے نکلتے وقت — اللہ کے فضل کا سوال۔$sb$, $sb$تُقال عند الخروج من المسجد — سؤال الله من فضله.$sb$),
  ($sb$masjid_adhan$sb$, $sb$قیامت کے دن نبی ﷺ کی شفاعت نصیب ہوتی ہے۔$sb$, $sb$تُنال شفاعة النبي ﷺ يوم القيامة.$sb$),
  ($sb$morning_1$sb$, $sb$اللہ اور بندے کے درمیان تقسیم — ہر آیت پر اس کا جواب۔$sb$, $sb$مقسومة بين الله وعبده — لكل آية جوابها منه.$sb$),
  ($sb$morning_2$sb$, $sb$شیطان اس کے اور اس کے گھر والوں کے قریب نہیں آئے گا۔$sb$, $sb$لا يقربه الشيطان ولا أهل بيته.$sb$),
  ($sb$morning_3$sb$, $sb$اللہ کی طرف سے محافظ؛ شیطان پوری رات قریب نہیں آ سکتا۔$sb$, $sb$حافظ من الله؛ لا يقربه شيطان طوال الليل.$sb$),
  ($sb$morning_4$sb$, $sb$یہ دس آیات پڑھنے پر شیطان گھر میں داخل نہیں ہوتا۔$sb$, $sb$لا يدخل الشيطان البيت إذا قُرئت هذه الآيات العشر.$sb$),
  ($sb$morning_5$sb$, $sb$یہ دس آیات پڑھنے پر شیطان گھر میں داخل نہیں ہوتا۔$sb$, $sb$لا يدخل الشيطان البيت إذا قُرئت هذه الآيات العشر.$sb$),
  ($sb$morning_6$sb$, $sb$انہیں رات کو پڑھنا اس کے لیے کافی ہے۔$sb$, $sb$قراءتهما في ليلة تكفيه.$sb$),
  ($sb$morning_7$sb$, $sb$انہیں رات کو پڑھنا اس کے لیے کافی ہے۔$sb$, $sb$قراءتهما في ليلة تكفيه.$sb$),
  ($sb$morning_8$sb$, $sb$انہیں رات کو پڑھنا اس کے لیے کافی ہے۔$sb$, $sb$قراءتهما في ليلة تكفيه.$sb$),
  ($sb$morning_9$sb$, $sb$صبح و شام پڑھیں — ہر چیز کے مقابلے میں کافی ہوں گی۔$sb$, $sb$تُقرأ صباحًا ومساءً — تكفيك من كل شيء.$sb$),
  ($sb$morning_10$sb$, $sb$صبح و شام پڑھیں — ہر چیز کے مقابلے میں کافی ہوں گی۔$sb$, $sb$تُقرأ صباحًا ومساءً — تكفيك من كل شيء.$sb$),
  ($sb$morning_11$sb$, $sb$صبح و شام پڑھیں — ہر چیز کے مقابلے میں کافی ہوں گی۔$sb$, $sb$تُقرأ صباحًا ومساءً — تكفيك من كل شيء.$sb$),
  ($sb$morning_12$sb$, $sb$بادشاہی، تمام حمد اور تمام معاملات اللہ ہی کے ہیں۔$sb$, $sb$الملك والحمد والأمر كله لله.$sb$),
  ($sb$morning_13$sb$, $sb$اسلام، اخلاص اور ملتِ ابراہیم کا اقرار۔$sb$, $sb$إقرار بالإسلام والإخلاص وملة إبراهيم.$sb$),
  ($sb$morning_14$sb$, $sb$اللہ ہی سے ہم جیتے اور مرتے ہیں، اسی کی طرف لوٹنا ہے۔$sb$, $sb$بالله نحيا ونموت وإليه النشور.$sb$),
  ($sb$morning_15$sb$, $sb$صبح و شام اللہ کی نعمت، عافیت اور پردہ پوشی۔$sb$, $sb$نعمة الله وعافيته وستره صباحًا ومساءً.$sb$),
  ($sb$morning_16$sb$, $sb$دن بھر کے شکر کا فریضہ ادا کر دیتی ہے۔$sb$, $sb$تؤدّي واجب شكر الله عن اليوم.$sb$),
  ($sb$morning_17$sb$, $sb$اس حمد کو اللہ خود لکھتا اور اس کا اجر دیتا ہے۔$sb$, $sb$يتولى الله بنفسه كتابة هذا الحمد ومجازاته.$sb$),
  ($sb$morning_18$sb$, $sb$اللہ کا وعدہ ہے کہ قیامت کے دن تمہیں راضی کرے گا۔$sb$, $sb$وعدُ الله أن يُرضيك يوم القيامة.$sb$),
  ($sb$morning_19$sb$, $sb$دین، اہل و عیال اور مال کے لیے عافیت اور حفاظت۔$sb$, $sb$عافية وحفظ في الدين والأهل والمال.$sb$),
  ($sb$morning_20$sb$, $sb$صبح سے کہی گئی ہر بات سے وزنی۔$sb$, $sb$تفوق وزنًا كل ما قيل منذ الصباح.$sb$),
  ($sb$morning_21$sb$, $sb$صبح و شام تین بار کہنے پر کوئی چیز نقصان نہیں پہنچاتی۔$sb$, $sb$لا يضرك شيء إذا قلتها ثلاث مرات صباحًا ومساءً.$sb$),
  ($sb$morning_22$sb$, $sb$چھوٹے اور بڑے دونوں شرک سے نجات دیتی ہے۔$sb$, $sb$تُخلّصك من صغير الشرك وكبيره.$sb$),
  ($sb$morning_23$sb$, $sb$اس جگہ سے جانے تک کوئی چیز نقصان نہیں پہنچاتی۔$sb$, $sb$لا يضرك شيء حتى ترحل من ذلك المكان.$sb$),
  ($sb$morning_24$sb$, $sb$نبی ﷺ نے ابو بکر کو صبح و شام کے لیے سکھائی۔$sb$, $sb$علّمها النبي ﷺ لأبي بكر صباحًا ومساءً.$sb$),
  ($sb$morning_25$sb$, $sb$نبی ﷺ نے فاطمہ کو صبح و شام کے لیے سکھائی۔$sb$, $sb$علّمها النبي ﷺ لفاطمة صباحًا ومساءً.$sb$),
  ($sb$morning_26$sb$, $sb$یقین کے ساتھ کہنے پر — اہلِ جنت میں سے ہوں گے۔$sb$, $sb$من قالها موقنًا بها — كان من أهل الجنة.$sb$),
  ($sb$morning_27$sb$, $sb$چار بار کہنے پر اللہ جہنم سے آزاد کر دیتا ہے۔$sb$, $sb$يعتقك الله من النار إذا قلتها أربع مرات.$sb$),
  ($sb$morning_28$sb$, $sb$صبح و شام جسم، سماعت اور بینائی کی حفاظت۔$sb$, $sb$حفظ للبدن والسمع والبصر صباحًا ومساءً.$sb$),
  ($sb$morning_29$sb$, $sb$جو کچھ تمہیں فکرمند کرے، اللہ اس کے لیے کافی ہو گا۔$sb$, $sb$يكفيك الله ما أهمّك.$sb$),
  ($sb$morning_30$sb$, $sb$اللہ سے دن کی فتح، نصرت، نور، برکت اور ہدایت کا سوال۔$sb$, $sb$سؤال الله فتح اليوم ونصره ونوره وبركته وهداه.$sb$),
  ($sb$morning_31$sb$, $sb$دس غلام آزاد کرنے کا اجر اور شیطان سے ڈھال۔$sb$, $sb$أجر عتق عشر رقاب وحرز من الشيطان.$sb$),
  ($sb$morning_32$sb$, $sb$گناہ معاف، چاہے سمندر کی جھاگ جتنے ہوں۔$sb$, $sb$تُغفر الذنوب ولو كانت مثل زبد البحر.$sb$),
  ($sb$bocp_122$sb$, $sb$اللہ کے کامل کلمات کی پناہ ہر مخلوق کے شر سے۔$sb$, $sb$استعاذة بكلمات الله التامات من شر ما خلق.$sb$),
  ($sb$bocp_123$sb$, $sb$اللہ کی عظیم ذات اور کامل کلمات کے واسطے ہر شر سے پناہ۔$sb$, $sb$استعاذة بوجه الله العظيم وكلماته التامات من كل شر.$sb$),
  ($sb$bocp_124$sb$, $sb$صبح کے وقت اقرار کہ بادشاہی اور حمد اللہ ہی کی ہے۔$sb$, $sb$إقرار صباحي بأن الملك والحمد لله.$sb$),
  ($sb$bocp_125$sb$, $sb$اللہ کی وحدانیت، بادشاہی، حمد اور ہر چیز پر قدرت کا اقرار۔$sb$, $sb$إقرار بوحدانية الله وملكه وحمده وقدرته على كل شيء.$sb$),
  ($sb$bocp_126$sb$, $sb$سستی، بڑھاپے، دنیاوی فتنوں اور عذابِ قبر سے پناہ۔$sb$, $sb$استعاذة من الكسل والهرم وفتنة الدنيا وعذاب القبر.$sb$),
  ($sb$bocp_127$sb$, $sb$صبح کے وقت اقرار کہ بادشاہی رب العالمین کی ہے۔$sb$, $sb$إقرار صباحي بأن الملك لله رب العالمين.$sb$),
  ($sb$bocp_128$sb$, $sb$اس دن کی کامیابی، نور، برکت اور ہدایت کا سوال۔$sb$, $sb$سؤال فتح اليوم ونوره وبركته وهداه.$sb$),
  ($sb$bocp_129$sb$, $sb$اللہ ہی سے ہم جیتے اور مرتے ہیں، اسی کی طرف اٹھائے جائیں گے۔$sb$, $sb$بالله نحيا ونموت وإليه النشور.$sb$),
  ($sb$bocp_130$sb$, $sb$نفس کے شر اور شیطان کے شرک سے پناہ۔$sb$, $sb$استعاذة من شر النفس ومن شرك الشيطان.$sb$),
  ($sb$bocp_131$sb$, $sb$صبح اللہ اور اس کے رسول ﷺ کی گواہی۔$sb$, $sb$شهادة صباحية لله ولرسوله ﷺ.$sb$),
  ($sb$bocp_132$sb$, $sb$دین، دنیا، اہل و عیال اور مال میں معافی اور عافیت کا سوال۔$sb$, $sb$سؤال العفو والعافية في الدين والدنيا والأهل والمال.$sb$),
  ($sb$bocp_133$sb$, $sb$آگے، پیچھے، دائیں، بائیں، اوپر اور نیچے سے حفاظت کا سوال۔$sb$, $sb$سؤال الحفظ من الجهات الست.$sb$),
  ($sb$bocp_134$sb$, $sb$اللہ کو رب، اسلام کو دین اور محمد ﷺ کو رسول ماننے پر راضی۔$sb$, $sb$الرضا بالله ربًا وبالإسلام دينًا وبمحمد ﷺ رسولًا.$sb$),
  ($sb$bocp_135$sb$, $sb$اقرار کہ ہر نعمت صرف اللہ ہی سے ہے۔$sb$, $sb$إقرار بأن كل نعمة من الله وحده.$sb$),
  ($sb$bocp_136$sb$, $sb$جسم، سماعت اور بینائی کی صحت کا سوال۔$sb$, $sb$سؤال العافية في البدن والسمع والبصر.$sb$),
  ($sb$bocp_137$sb$, $sb$کفر، فقر اور عذابِ قبر سے پناہ۔$sb$, $sb$استعاذة من الكفر والفقر وعذاب القبر.$sb$),
  ($sb$bocp_138$sb$, $sb$ہر چیز پر اللہ کی قدرت اور علم کا اقرار۔$sb$, $sb$إقرار بقدرة الله وإحاطة علمه بكل شيء.$sb$),
  ($sb$bocp_139$sb$, $sb$اسلام، اخلاص اور ملتِ ابراہیم کا اقرار۔$sb$, $sb$إقرار بالإسلام والإخلاص وملة إبراهيم.$sb$),
  ($sb$bocp_140$sb$, $sb$اللہ کی رحمت کے واسطے پلک جھپکنے کے برابر بھی نفس کے حوالے نہ کیے جانے کا سوال۔$sb$, $sb$سؤال ألا يكِلنا الله إلى أنفسنا طرفة عين برحمته.$sb$),
  ($sb$bocp_141$sb$, $sb$سیدِ استغفار — جو اسے کہہ کر مرے، جنتی ہے۔$sb$, $sb$سيد الاستغفار — من قالها ومات دخل الجنة.$sb$),
  ($sb$bocp_142$sb$, $sb$اللہ سے اس کی ذات کے نور کے واسطے قبولیت اور جہنم سے پناہ کا سوال۔$sb$, $sb$سؤال الله بنور وجهه القبول والإجارة من النار.$sb$),
  ($sb$bocp_143$sb$, $sb$اللہ کافی ہے — وہ عرشِ عظیم کا رب ہے۔$sb$, $sb$الله يكفي — وهو رب العرش العظيم.$sb$),
  ($sb$bocp_144$sb$, $sb$فکر، غم، بزدلی، بخل، قرض اور ظلم سے پناہ۔$sb$, $sb$استعاذة من الهم والحزن والجبن والبخل والدَّين والقهر.$sb$),
  ($sb$bocp_145$sb$, $sb$صبح کے وقت اقرار کہ ساری بادشاہی صرف اللہ کی ہے۔$sb$, $sb$إقرار صباحي بأن كل السلطان لله وحده.$sb$),
  ($sb$nature_rain$sb$, $sb$نبی ﷺ تازہ بارش میں کھڑے ہو جاتے — یہ اپنے رب کی طرف سے آتی ہے۔$sb$, $sb$كان النبي ﷺ يتعرّض للمطر — إنه حديث عهد بربه.$sb$),
  ($sb$nature_thunder$sb$, $sb$گرج سنتے وقت — فرشتے خوف سے اللہ کی تسبیح کرتے ہیں۔$sb$, $sb$تُقال عند سماع الرعد — تسبّح الملائكة الله من خشيته.$sb$),
  ($sb$nightmares_1$sb$, $sb$بائیں طرف تین بار تھوکیں اور برا خواب نقصان نہیں پہنچائے گا۔$sb$, $sb$انفث عن يسارك ثلاثًا فلن يضرك الحلم.$sb$),
  ($sb$nightmares_2$sb$, $sb$تین بار بائیں تھوکیں اور کروٹ بدلیں — برا خواب نقصان نہیں پہنچائے گا۔$sb$, $sb$انفث عن يسارك ثلاثًا وتحوّل عن جنبك — لن يضرك الحلم.$sb$),
  ($sb$post_prayer_subhanallah$sb$, $sb$ہر نماز کے بعد 33 بار — گناہ سمندر کی جھاگ کی طرح معاف۔$sb$, $sb$33 مرة بعد كل صلاة — تُغفر الذنوب ولو كانت مثل زبد البحر.$sb$),
  ($sb$post_prayer_alhamdulillah$sb$, $sb$نیکیوں کا میزان بھر دیتی ہے۔$sb$, $sb$تملأ ميزان الحسنات.$sb$),
  ($sb$post_prayer_allahu_akbar$sb$, $sb$33 بار کہی جاتی ہے — نماز کے بعد 100 اذکار مکمل ہوتے ہیں۔$sb$, $sb$تُقال 33 مرة — تُكمل 100 ذكر بعد الصلاة.$sb$),
  ($sb$post_prayer_ayat_kursi$sb$, $sb$آپ اور جنت کے درمیان صرف موت حائل ہے۔$sb$, $sb$لا يحول بينك وبين الجنة إلا الموت.$sb$),
  ($sb$post_prayer_la_ilaha$sb$, $sb$گناہ معاف، چاہے سمندر کی جھاگ جتنے ہوں۔$sb$, $sb$تُغفر الذنوب ولو كانت مثل زبد البحر.$sb$),
  ($sb$post_prayer_istighfar$sb$, $sb$نبی ﷺ ہر نماز کے بعد تین بار استغفار کرتے تھے۔$sb$, $sb$كان النبي ﷺ يستغفر ثلاثًا بعد كل صلاة.$sb$),
  ($sb$bocp_043$sb$, $sb$دنیا اور آخرت کی بھلائی اور جہنم سے پناہ کا سوال۔$sb$, $sb$سؤال حسنة الدنيا والآخرة والوقاية من النار.$sb$),
  ($sb$bocp_044$sb$, $sb$عذابِ قبر، دجال اور سستی سے پناہ؛ دل کو پاک کرتی ہے۔$sb$, $sb$استعاذة من عذاب القبر والدجال والكسل؛ تنقّي القلب.$sb$),
  ($sb$bocp_045$sb$, $sb$کمزوری، بزدلی، بڑھاپے اور عذابِ قبر سے پناہ۔$sb$, $sb$استعاذة من العجز والجبن والهرم وعذاب القبر.$sb$),
  ($sb$bocp_046$sb$, $sb$سخت آزمائش، بدبختی، برے فیصلے اور دشمنوں کی خوشی سے پناہ۔$sb$, $sb$استعاذة من جهد البلاء ودرك الشقاء وسوء القضاء وشماتة الأعداء.$sb$),
  ($sb$bocp_047$sb$, $sb$اللہ سے دین، دنیا اور آخرت کی درستی کا سوال۔$sb$, $sb$سؤال إصلاح الدين والدنيا والآخرة.$sb$),
  ($sb$bocp_048$sb$, $sb$ہدایت، تقویٰ، عفت اور غنا کا سوال۔$sb$, $sb$سؤال الهدى والتقى والعفاف والغنى.$sb$),
  ($sb$bocp_049$sb$, $sb$بے فائدہ علم، بے خوف دل اور نہ سیر ہونے والے نفس سے پناہ۔$sb$, $sb$استعاذة من علم لا ينفع وقلب لا يخشع ونفس لا تشبع.$sb$),
  ($sb$bocp_050$sb$, $sb$ہدایت اور درست سمت کا سوال۔$sb$, $sb$سؤال الهدى والسداد.$sb$),
  ($sb$bocp_051$sb$, $sb$نعمت اور عافیت کے چھن جانے اور اللہ کے اچانک غضب سے پناہ۔$sb$, $sb$استعاذة من زوال النعمة وتحوّل العافية وفجاءة النقمة.$sb$),
  ($sb$bocp_052$sb$, $sb$بابرکت مال، نیک اولاد اور اطاعت میں لمبی زندگی کا سوال۔$sb$, $sb$سؤال المال المبارك والولد الصالح والعمر الطويل في الطاعة.$sb$),
  ($sb$bocp_053$sb$, $sb$اللہ کو واحد لائق عبادت اور مالکِ عرش ماننے کا اقرار۔$sb$, $sb$إقرار بأن الله وحده المستحق للعبادة — رب العرش.$sb$),
  ($sb$bocp_054$sb$, $sb$پلک جھپکنے کے برابر بھی اپنے نفس کے حوالے نہ کیے جانے کا سوال۔$sb$, $sb$سؤال ألا يكِلنا الله إلى أنفسنا طرفة عين.$sb$),
  ($sb$bocp_055$sb$, $sb$دعائے یونس — کوئی مسلمان اسے نہ کہے سوائے اس کے کہ اللہ اسے جواب دے۔$sb$, $sb$دعوة يونس — ما دعا بها مسلم إلا استجاب الله له.$sb$),
  ($sb$bocp_056$sb$, $sb$قرآن دل کی بہار، سینے کا نور اور غم کا مٹانے والا بننے کا سوال۔$sb$, $sb$سؤال أن يكون القرآن ربيع القلب وذهاب الهم.$sb$),
  ($sb$bocp_057$sb$, $sb$اللہ سے دل کو اپنی اطاعت کی طرف پھیرنے کا سوال۔$sb$, $sb$سؤال الله أن يصرف القلوب إلى طاعته.$sb$),
  ($sb$bocp_058$sb$, $sb$اللہ سے دل کو دین پر ثابت رکھنے کا سوال۔$sb$, $sb$سؤال تثبيت القلب على دين الله.$sb$),
  ($sb$bocp_059$sb$, $sb$دنیا اور آخرت میں عافیت کا سوال۔$sb$, $sb$سؤال العافية في الدنيا والآخرة.$sb$),
  ($sb$bocp_060$sb$, $sb$اچھے انجام اور دنیاوی رسوائی سے پناہ کا سوال۔$sb$, $sb$سؤال حسن العاقبة والإجارة من خزي الدنيا.$sb$),
  ($sb$bocp_061$sb$, $sb$اللہ سے مدد، فتح، مقبول توبہ اور ہدایت یافتہ دل کا سوال۔$sb$, $sb$سؤال العون والنصر وقبول التوبة وهداية القلب.$sb$),
  ($sb$bocp_062$sb$, $sb$کان، آنکھ، زبان، دل اور نطفے کے شر سے پناہ۔$sb$, $sb$استعاذة من شر السمع والبصر واللسان والقلب والمني.$sb$),
  ($sb$bocp_063$sb$, $sb$معاف کرنے والا اور معافی سے محبت کرنے والا اللہ سے معافی کا سوال۔$sb$, $sb$سؤال العفو من العفوّ الذي يحب العفو.$sb$),
  ($sb$bocp_064$sb$, $sb$نیکی، مسکینوں سے محبت اور فتنے سے پاک موت کا سوال۔$sb$, $sb$سؤال فعل الخيرات وحب المساكين والوفاة بلا فتنة.$sb$),
  ($sb$bocp_065$sb$, $sb$معلوم و نامعلوم ہر خیر کا سوال اور ہر شر سے پناہ۔$sb$, $sb$سؤال كل خير والاستعاذة من كل شر — علِم منه وما لم يعلم.$sb$),
  ($sb$bocp_066$sb$, $sb$کھڑے، بیٹھے اور لیٹے اسلام پر حفاظت کا سوال۔$sb$, $sb$سؤال الحفظ بالإسلام قائمًا وقاعدًا وراقدًا.$sb$),
  ($sb$bocp_067$sb$, $sb$بزدلی، بخل، نکمے بڑھاپے اور دنیاوی فتنے سے پناہ۔$sb$, $sb$استعاذة من الجبن والبخل وأرذل العمر وفتنة الدنيا.$sb$),
  ($sb$bocp_068$sb$, $sb$غلطیوں، جہالت اور جان بوجھ کر کیے گناہوں — سب کی مغفرت کا سوال۔$sb$, $sb$سؤال المغفرة للخطأ والجهل والعمد.$sb$),
  ($sb$bocp_069$sb$, $sb$اپنے آپ پر بہت ظلم کرنے کی خاص مغفرت کا سوال۔$sb$, $sb$سؤال مغفرة خاصة من الله على ظلم النفس الكثير.$sb$),
  ($sb$bocp_070$sb$, $sb$صرف اللہ کے سامنے سرِ تسلیم، ایمان اور توکل کا اقرار۔$sb$, $sb$إقرار بالإسلام والإيمان والتوكل على الله وحده.$sb$),
  ($sb$bocp_071$sb$, $sb$رحمت، مغفرت، جنت اور جہنم سے نجات کے اسباب کا سوال۔$sb$, $sb$سؤال موجبات الرحمة والمغفرة والفوز بالجنة والنجاة من النار.$sb$),
  ($sb$bocp_072$sb$, $sb$معلوم و نامعلوم ہر شر سے پناہ۔$sb$, $sb$استعاذة من كل شر — علِم منه وما لم يعلم.$sb$),
  ($sb$bocp_073$sb$, $sb$بڑھاپے اور زندگی کے اختتام پر رزق کی کشادگی کا سوال۔$sb$, $sb$سؤال سعة الرزق عند الكبر وانقطاع العمر.$sb$),
  ($sb$bocp_074$sb$, $sb$گناہوں کی معافی، گھر میں کشادگی اور رزق میں برکت کا سوال۔$sb$, $sb$سؤال المغفرة والسعة في الدار والبركة في الرزق.$sb$),
  ($sb$bocp_075$sb$, $sb$اللہ کے فضل اور رحمت کا سوال — جس کا صرف وہی مالک ہے۔$sb$, $sb$سؤال الله فضله ورحمته — لا يملكهما إلا هو.$sb$),
  ($sb$bocp_076$sb$, $sb$بلندی سے گرنے، ڈوبنے، جلنے اور بری موت سے پناہ۔$sb$, $sb$استعاذة من التردي والغرق والحرق وسوء الموت.$sb$),
  ($sb$bocp_077$sb$, $sb$کمزوری، فسق، ریا، جذام اور بری بیماریوں سے پناہ۔$sb$, $sb$استعاذة من العجز والفسق والرياء والجذام وسيئ الأسقام.$sb$),
  ($sb$bocp_078$sb$, $sb$فقر، ذلت اور ظلم کرنے یا ظلم سہنے سے پناہ۔$sb$, $sb$استعاذة من الفقر والذلة والظلم — أن أَظلم أو أُظلم.$sb$),
  ($sb$bocp_079$sb$, $sb$بے خوف دل، غیر قبول دعا اور بے فائدہ علم سے پناہ۔$sb$, $sb$استعاذة من قلب لا يخشع ودعاء لا يُسمع وعلم لا ينفع.$sb$),
  ($sb$bocp_080$sb$, $sb$برے دن، رات، ساعت، ساتھی اور پڑوسی سے پناہ۔$sb$, $sb$استعاذة من يوم السوء وليلة السوء وصاحب السوء وجار السوء.$sb$),
  ($sb$bocp_081$sb$, $sb$جنت کا سوال اور جہنم سے پناہ۔$sb$, $sb$سؤال الجنة والاستعاذة من النار.$sb$),
  ($sb$bocp_082$sb$, $sb$اللہ سے دین کی گہری سمجھ کا سوال۔$sb$, $sb$سؤال الله الفقه في الدين.$sb$),
  ($sb$bocp_083$sb$, $sb$معلوم و نامعلوم شرک سے پناہ اور مغفرت کا سوال۔$sb$, $sb$استعاذة من الشرك المعلوم ومغفرة المجهول.$sb$),
  ($sb$bocp_084$sb$, $sb$نفع بخش علم، پاکیزہ رزق اور مقبول اعمال کا سوال۔$sb$, $sb$سؤال العلم النافع والرزق الطيب والعمل المتقبَّل.$sb$),
  ($sb$bocp_085$sb$, $sb$نفع بخش علم کا سوال اور بے فائدہ علم سے پناہ۔$sb$, $sb$سؤال العلم النافع والاستعاذة من علم لا ينفع.$sb$),
  ($sb$bocp_086$sb$, $sb$اللہ سے اس کی وحدانیت اور بے نیازی کے واسطے مغفرت کا سوال۔$sb$, $sb$سؤال الله بوحدانيته وصمديته المغفرة.$sb$),
  ($sb$bocp_087$sb$, $sb$اللہ کی ثنا — اول، آخر، ظاہر اور باطن۔$sb$, $sb$ثناء على الله — الأول والآخر والظاهر والباطن.$sb$),
  ($sb$bocp_088$sb$, $sb$اللہ سے اس کے ناموں کے واسطے جنت اور جہنم سے پناہ کا سوال۔$sb$, $sb$سؤال الله بأسمائه الجنة والاستعاذة من النار.$sb$),
  ($sb$bocp_089$sb$, $sb$اللہ سے مغفرت اور توبہ کی قبولیت کا سوال۔$sb$, $sb$سؤال المغفرة وقبول التوبة.$sb$),
  ($sb$bocp_090$sb$, $sb$بہتر ہو تو زندگی، بہتر ہو تو موت، اور اللہ سے ملاقات کی چاہت کا سوال۔$sb$, $sb$سؤال الحياة إن كانت خيرًا والوفاة إن كانت خيرًا والشوق إلى لقاء الله.$sb$),
  ($sb$bocp_091$sb$, $sb$اللہ سے گناہوں سے ایسے پاک کرنے کا سوال جیسے سفید کپڑا میل سے پاک ہوتا ہے۔$sb$, $sb$سؤال التطهير من الذنوب كما يُنقّى الثوب الأبيض.$sb$),
  ($sb$bocp_092$sb$, $sb$جبرائیل، میکائیل اور اسرافیل کے رب سے آگ اور قبر سے پناہ۔$sb$, $sb$استعاذة برب جبريل وميكائيل وإسرافيل من النار والقبر.$sb$),
  ($sb$bocp_093$sb$, $sb$اللہ سے ہدایت اور نفس کے شر سے پناہ کا سوال۔$sb$, $sb$سؤال الإلهام والاستعاذة من شر النفس.$sb$),
  ($sb$bocp_094$sb$, $sb$اللہ سے قرض کی ادائیگی اور فقر سے بچاؤ کا سوال۔$sb$, $sb$سؤال الله قضاء الدَّين والغنى عن الفقر.$sb$),
  ($sb$bocp_095$sb$, $sb$اللہ سے دلوں کو ملانے اور راہِ سلامتی کی طرف ہدایت کا سوال۔$sb$, $sb$سؤال الله تأليف القلوب والهداية إلى سبل السلام.$sb$),
  ($sb$bocp_096$sb$, $sb$بری اخلاق، خواہشات، اعمال اور بیماریوں سے پناہ۔$sb$, $sb$استعاذة من منكرات الأخلاق والأهواء والأعمال والأدواء.$sb$),
  ($sb$bocp_097$sb$, $sb$قیامت کے دن آسان حساب کا سوال۔$sb$, $sb$سؤال الحساب اليسير يوم القيامة.$sb$),
  ($sb$bocp_098$sb$, $sb$اللہ کے ذکر، شکر اور بہترین عبادت میں مدد کا سوال۔$sb$, $sb$سؤال العون على الذكر والشكر وحسن العبادة.$sb$),
  ($sb$bocp_099$sb$, $sb$غیر متزلزل ایمان اور جنت میں نبی ﷺ کی رفاقت کا سوال۔$sb$, $sb$سؤال إيمان لا يرتد ومرافقة النبي ﷺ في الجنة.$sb$),
  ($sb$bocp_100$sb$, $sb$نفس سے پناہ، ہدایت اور ہر گناہ کی معافی کا سوال۔$sb$, $sb$سؤال الوقاية من النفس والهداية ومغفرة كل ذنب.$sb$),
  ($sb$bocp_101$sb$, $sb$قرض کے غلبے، دشمن کے غلبے اور دشمنوں کی خوشی سے پناہ۔$sb$, $sb$استعاذة من غلبة الدَّين وغلبة العدو وشماتة الأعداء.$sb$),
  ($sb$bocp_102$sb$, $sb$جنت کا سوال اور جہنم سے پناہ۔$sb$, $sb$سؤال الجنة والاستعاذة من النار.$sb$),
  ($sb$bocp_103$sb$, $sb$مغفرت، ہدایت، رزق اور آسان کھڑے ہونے کا سوال۔$sb$, $sb$سؤال المغفرة والهداية والرزق واليسر يوم القيامة.$sb$),
  ($sb$bocp_104$sb$, $sb$سماعت اور بصارت کی حفاظت اور ظالموں پر انصاف کی دعا۔$sb$, $sb$طلب حفظ السمع والبصر والانتصار من الظالم.$sb$),
  ($sb$bocp_105$sb$, $sb$اللہ کی ثنا — موجد، ہمیشہ زندہ، قائم و دائم۔$sb$, $sb$ثناء على الله — البديع الحي القيوم.$sb$),
  ($sb$bocp_106$sb$, $sb$اقرار کہ اللہ حق ہے — اس کا کلام، وعدہ اور اس سے ملاقات۔$sb$, $sb$إقرار بأن الله الحق — وعده ولقاؤه وقوله.$sb$),
  ($sb$bocp_107$sb$, $sb$اللہ کے سامنے سرِ تسلیم اور اگلے پچھلے گناہوں کی معافی کا سوال۔$sb$, $sb$إسلام لله وسؤال المغفرة لما تقدم وما تأخر.$sb$),
  ($sb$bocp_108$sb$, $sb$دعائے قنوت — ہدایت، عافیت اور طے شدہ شر سے پناہ۔$sb$, $sb$دعاء القنوت — الهداية والعافية والوقاية من شر القضاء.$sb$),
  ($sb$bocp_109$sb$, $sb$نبی ﷺ کے مانگے ہر خیر اور جس سے پناہ مانگی اس سے پناہ کا سوال۔$sb$, $sb$سؤال ما سأله النبي ﷺ من خير والاستعاذة مما استعاذ منه.$sb$),
  ($sb$bocp_110$sb$, $sb$سیدِ استغفار — جو اسے یقین سے کہے، جنتی ہے۔$sb$, $sb$سيد الاستغفار — من قالها موقنًا بها كان من أهل الجنة.$sb$),
  ($sb$bocp_111$sb$, $sb$اللہ سے ہر شر اور فاسقوں کی سازش سے کفایت کا سوال۔$sb$, $sb$سؤال الله كفاية شر الأشرار وكيد الفجار.$sb$),
  ($sb$bocp_112$sb$, $sb$سماعت، بینائی، ذات، اہل، زندگی اور عمل میں برکت کا سوال۔$sb$, $sb$سؤال البركة في السمع والبصر والخَلق والأهل والحياة والعمل.$sb$),
  ($sb$bocp_113$sb$, $sb$ہر گناہ کی معافی — چھوٹے، بڑے، پہلے، آخری۔$sb$, $sb$سؤال المغفرة لكل ذنب — دقيقه وجليله وأوله وآخره.$sb$),
  ($sb$bocp_114$sb$, $sb$اقرار کہ اللہ کی دی ہوئی چیز کوئی روک نہیں سکتا اور روکی ہوئی کوئی دے نہیں سکتا۔$sb$, $sb$إقرار بأنه لا مانع لما أعطى ولا معطي لما منع.$sb$),
  ($sb$bocp_115$sb$, $sb$مغفرت، رحمت، ہدایت، رزق اور رفعت کا سوال۔$sb$, $sb$سؤال المغفرة والرحمة والهداية والرزق والرفعة.$sb$),
  ($sb$bocp_116$sb$, $sb$اللہ سے فضل بڑھانے اور کم نہ کرنے کا سوال۔$sb$, $sb$سؤال الزيادة في الفضل وعدم النقصان.$sb$),
  ($sb$bocp_117$sb$, $sb$جیسے اللہ نے صورت اچھی بنائی، اسی طرح سیرت اچھی بنانے کا سوال۔$sb$, $sb$كما أحسن الله خَلقك اسأله أن يحسن خُلقك.$sb$),
  ($sb$bocp_118$sb$, $sb$اللہ سے ثابت قدمی اور دوسروں کے لیے رہنما بننے کا سوال۔$sb$, $sb$سؤال الله التثبيت والهداية للناس.$sb$),
  ($sb$bocp_119$sb$, $sb$اللہ سے حکمت کا سوال — جسے یہ ملی، بہت خیر ملی۔$sb$, $sb$سؤال الحكمة — من أوتيها فقد أوتي خيرًا كثيرًا.$sb$),
  ($sb$bocp_120$sb$, $sb$اللہ کے نام کے ساتھ — زمین یا آسمان کی کوئی چیز نقصان نہیں پہنچا سکتی۔$sb$, $sb$باسم الله — لا يضر معه شيء في الأرض ولا في السماء.$sb$),
  ($sb$bocp_121$sb$, $sb$انسانوں اور جنوں کے ہر شیطان سے پناہ۔$sb$, $sb$استعاذة من كل شيطان — إنس وجان.$sb$),
  ($sb$quranic_fatiha$sb$, $sb$اللہ اور بندے کے درمیان تقسیم — ہر آیت پر اس کا جواب۔$sb$, $sb$مقسومة بين الله وعبده — لكل آية جوابها منه.$sb$),
  ($sb$quranic_ikhlas$sb$, $sb$قرآن کے تہائی حصے کے برابر۔$sb$, $sb$تعدل ثلث القرآن.$sb$),
  ($sb$quranic_falaq$sb$, $sb$ہر مخلوقی شر سے پناہ — تاریک رات، حسد اور جادو۔$sb$, $sb$استعاذة من شر ما خلق — الليل والحسد والسحر.$sb$),
  ($sb$quranic_nas$sb$, $sb$انسانوں کے وسواس ڈالنے والے شر سے پناہ۔$sb$, $sb$استعاذة من الوسواس الخنّاس.$sb$),
  ($sb$bocp_001$sb$, $sb$کعبہ اٹھاتے وقت ابراہیم کی دعا — قبولیت اور توبہ کا سوال۔$sb$, $sb$دعاء إبراهيم عند رفع الكعبة — قبول وتوبة.$sb$),
  ($sb$bocp_002$sb$, $sb$دنیا اور آخرت کی بھلائی اور جہنم سے پناہ کا سوال۔$sb$, $sb$سؤال حسنة الدنيا والآخرة والوقاية من النار.$sb$),
  ($sb$bocp_003$sb$, $sb$اللہ سے صبر، ثابت قدمی اور نصرت کا سوال۔$sb$, $sb$سؤال الصبر والتثبيت والنصر.$sb$),
  ($sb$bocp_004$sb$, $sb$بھول اور طاقت سے زیادہ بوجھ کی معافی کا سوال۔$sb$, $sb$سؤال العفو عن الخطأ وعدم تحمّل ما لا طاقة له.$sb$),
  ($sb$bocp_005$sb$, $sb$ہدایت کے بعد دلوں کو ٹیڑھا نہ ہونے کا سوال۔$sb$, $sb$سؤال ألا يزيغ القلوب بعد الهداية.$sb$),
  ($sb$bocp_006$sb$, $sb$ہم ایمان لائے، ہمارے گناہ معاف کر اور جہنم سے بچا۔$sb$, $sb$آمنّا فاغفر لنا ذنوبنا وقنا عذاب النار.$sb$),
  ($sb$bocp_007$sb$, $sb$اللہ کی حکمتِ تخلیق کا اقرار — جہنم سے پناہ۔$sb$, $sb$إقرار بحكمة الله في الخلق والاستعاذة من النار.$sb$),
  ($sb$bocp_008$sb$, $sb$جسے تو نے جہنم میں ڈالا، اسے رسوا کیا۔$sb$, $sb$من تُدخل النار فقد أخزيته.$sb$),
  ($sb$bocp_009$sb$, $sb$ہم نے سنا، ایمان لائے — گناہ معاف کر اور نیکوں کے ساتھ اٹھا۔$sb$, $sb$سمعنا فآمنّا فاغفر لنا وتوفّنا مع الأبرار.$sb$),
  ($sb$bocp_010$sb$, $sb$اللہ سے وعدے کی تکمیل اور قیامت کے دن رسوائی نہ ہونے کا سوال۔$sb$, $sb$سؤال وعد الله وعدم الخزي يوم القيامة.$sb$),
  ($sb$bocp_011$sb$, $sb$دعائے آدم — گناہ کا اقرار اور مغفرت کی درخواست۔$sb$, $sb$دعوة آدم — اعتراف بالذنب وطلب المغفرة.$sb$),
  ($sb$bocp_012$sb$, $sb$ظالموں کے لیے آزمائش نہ بننے اور رحمت سے نجات کا سوال۔$sb$, $sb$سؤال ألا نكون فتنة للظالمين والنجاة برحمة الله.$sb$),
  ($sb$bocp_013$sb$, $sb$اپنے اور پہلے ایمان لانے والوں کے لیے مغفرت — مومنوں سے بغض نہ ہو۔$sb$, $sb$سؤال المغفرة للنفس والسابقين — بلا غل تجاه المؤمنين.$sb$),
  ($sb$bocp_014$sb$, $sb$اپنے، والدین اور تمام مومنوں کے لیے مغفرت کا سوال۔$sb$, $sb$سؤال المغفرة للنفس والوالدين وجميع المؤمنين.$sb$),
  ($sb$bocp_015$sb$, $sb$اے میرے رب، میرے علم میں اضافہ فرما۔$sb$, $sb$ربّ زدني علمًا.$sb$),
  ($sb$bocp_016$sb$, $sb$شیاطین کے وسوسوں اور ان کی حاضری سے پناہ۔$sb$, $sb$استعاذة من همزات الشياطين وحضورهم.$sb$),
  ($sb$bocp_017$sb$, $sb$بابرکت ٹھکانے کا سوال — کشتی سے اترتے وقت نوح کی دعا۔$sb$, $sb$سؤال منزل مبارك — دعوة نوح عند نزوله.$sb$),
  ($sb$bocp_018$sb$, $sb$اے میرے رب، ان دونوں پر رحم فرما جیسے انہوں نے مجھے چھوٹا پالا۔$sb$, $sb$ربّ ارحمهما كما ربّياني صغيرًا.$sb$),
  ($sb$bocp_019$sb$, $sb$بیویوں اور اولاد میں آنکھوں کی ٹھنڈک کا سوال۔$sb$, $sb$سؤال قرة العين من الأزواج والذرية.$sb$),
  ($sb$bocp_020$sb$, $sb$اللہ سے اپنی اور اہل کی برے اعمال سے نجات کا سوال۔$sb$, $sb$سؤال النجاة للنفس والأهل من أعمال السوء.$sb$),
  ($sb$bocp_021$sb$, $sb$معاف فرما، رحم فرما — تو بہترین رحم کرنے والا ہے۔$sb$, $sb$اغفر وارحم — أنت خير الراحمين.$sb$),
  ($sb$bocp_022$sb$, $sb$زکریا کی اولاد کے لیے دعا۔$sb$, $sb$دعوة زكريا في طلب الذرية.$sb$),
  ($sb$bocp_023$sb$, $sb$موسیٰ کی فصاحت کی دعا — دل کھولے اور زبان کو کھول دے۔$sb$, $sb$دعوة موسى للفصاحة — يشرح الصدر ويحلّ العقدة.$sb$),
  ($sb$bocp_024$sb$, $sb$اے میرے رب، میرے علم میں اضافہ فرما۔$sb$, $sb$ربّ زدني علمًا.$sb$),
  ($sb$bocp_025$sb$, $sb$موسیٰ کی دعا — اے میرے رب، جو خیر تو اتارے میں اس کا محتاج ہوں۔$sb$, $sb$دعوة موسى — ربّ إني لما أنزلت إليّ من خير فقير.$sb$),
  ($sb$bocp_026$sb$, $sb$نوح کی دعا — بغیر علم کے سوال کرنے سے پناہ۔$sb$, $sb$دعوة نوح — الاستعاذة من السؤال بلا علم.$sb$),
  ($sb$bocp_027$sb$, $sb$مصر میں موسیٰ کی دعا — میں نے اپنے آپ پر ظلم کیا، مجھے معاف فرما۔$sb$, $sb$دعوة موسى في مصر — ظلمت نفسي فاغفر لي.$sb$),
  ($sb$bocp_028$sb$, $sb$ابراہیم کی دعا — اپنے اور اولاد کے لیے قیامِ نماز۔$sb$, $sb$دعوة إبراهيم — إقامة الصلاة للنفس والذرية.$sb$),
  ($sb$bocp_029$sb$, $sb$ابراہیم کی نیک اولاد کے لیے دعا۔$sb$, $sb$دعوة إبراهيم لولد صالح.$sb$),
  ($sb$bocp_030$sb$, $sb$ابراہیم کی دعا — اپنے، والدین اور تمام مومنوں کے لیے مغفرت۔$sb$, $sb$دعوة إبراهيم — المغفرة للنفس والوالدين وجميع المؤمنين.$sb$),
  ($sb$bocp_031$sb$, $sb$اللہ کافی ہے — جو سات بار کہے، اللہ اس کے لیے کافی ہو جاتا ہے۔$sb$, $sb$الله يكفي — من قالها سبعًا كفاه الله.$sb$),
  ($sb$bocp_032$sb$, $sb$مچھلی کے پیٹ میں یونس کی دعا۔$sb$, $sb$دعوة يونس في بطن الحوت.$sb$),
  ($sb$bocp_033$sb$, $sb$اللہ سے جہنم کے عذاب کو دور کرنے کا سوال۔$sb$, $sb$سؤال الله صرف عذاب جهنم.$sb$),
  ($sb$bocp_034$sb$, $sb$بیویوں اور اولاد میں آنکھوں کی ٹھنڈک کا سوال۔$sb$, $sb$سؤال قرة العين من الأزواج والذرية.$sb$),
  ($sb$bocp_035$sb$, $sb$اصحابِ کہف کی دعا — رحمت اور ہر معاملے میں ہدایت۔$sb$, $sb$دعوة أصحاب الكهف — الرحمة والرشد في الأمر.$sb$),
  ($sb$bocp_036$sb$, $sb$سلیمان کی دعا — شکر گزاری اور اولاد کی نیکی کا سوال۔$sb$, $sb$دعوة سليمان — الشكر وإصلاح الذرية.$sb$),
  ($sb$bocp_037$sb$, $sb$حواریوں کی دعا — مغفرت، ثابت قدمی اور نصرت۔$sb$, $sb$دعوة الحواريين — المغفرة والتثبيت والنصر.$sb$),
  ($sb$bocp_038$sb$, $sb$ابراہیم اور اس کے ساتھیوں کی دعا — توکل، رجوع اور آزمائش سے پناہ۔$sb$, $sb$دعوة إبراهيم وأتباعه — التوكل والإنابة والاستعاذة من الفتنة.$sb$),
  ($sb$bocp_039$sb$, $sb$اللہ سے پل صراط پر ہمارے نور کی تکمیل اور مغفرت کا سوال۔$sb$, $sb$سؤال إتمام النور والمغفرة على الصراط.$sb$),
  ($sb$bocp_040$sb$, $sb$اپنے اور پہلے ایمان لانے والوں کے لیے مغفرت — مومنوں سے بغض نہ ہو۔$sb$, $sb$المغفرة للنفس والسابقين — بلا غل تجاه المؤمنين.$sb$),
  ($sb$bocp_041$sb$, $sb$تجھی پر بھروسہ، تیری ہی طرف رجوع اور تیری ہی طرف لوٹنا ہے۔$sb$, $sb$عليك توكلنا وإليك أنبنا وإليك المصير.$sb$),
  ($sb$bocp_042$sb$, $sb$آسیہ کی دعا — جنت میں گھر اور ظالم سے نجات۔$sb$, $sb$دعوة آسية — بيت في الجنة والنجاة من الظالم.$sb$),
  ($sb$rabbana_001$sb$, $sb$کعبہ اٹھاتے وقت ابراہیم — سمیع سے قبولیت کا سوال۔$sb$, $sb$إبراهيم عند رفع الكعبة — سؤال القبول من السميع.$sb$),
  ($sb$rabbana_002$sb$, $sb$ابراہیم اور اسماعیل کی اپنے اور اولاد کے مسلم رہنے کی دعا۔$sb$, $sb$دعوة إبراهيم وإسماعيل — الإسلام لنفسيهما وذريتهما.$sb$),
  ($sb$rabbana_003$sb$, $sb$ابراہیم کی دعا — نبی محمد ﷺ کی بعثت سے قبول ہوئی۔$sb$, $sb$دعوة إبراهيم استُجيبت ببعثة النبي محمد ﷺ.$sb$),
  ($sb$rabbana_004$sb$, $sb$دنیا اور آخرت کی بھلائی اور جہنم سے پناہ کا سوال۔$sb$, $sb$سؤال حسنة الدنيا والآخرة والوقاية من النار.$sb$),
  ($sb$rabbana_005$sb$, $sb$اللہ سے صبر، ثابت قدمی اور نصرت کا سوال۔$sb$, $sb$سؤال الصبر والتثبيت والنصر.$sb$),
  ($sb$rabbana_006$sb$, $sb$اللہ سے بھول اور خطا پر پکڑ نہ کرنے کا سوال۔$sb$, $sb$سؤال ألا يؤاخذنا الله بالنسيان والخطأ.$sb$),
  ($sb$rabbana_007$sb$, $sb$اللہ سے ایسا بوجھ نہ ڈالنے کا سوال جیسا پہلوں پر ڈالا۔$sb$, $sb$سؤال ألا يحمّلنا الله إصرًا كالسابقين.$sb$),
  ($sb$rabbana_008$sb$, $sb$معافی، مغفرت، رحمت اور نصرت کا سوال۔$sb$, $sb$سؤال العفو والمغفرة والرحمة والنصر.$sb$),
  ($sb$rabbana_009$sb$, $sb$ہدایت کے بعد دلوں کو ٹیڑھا نہ ہونے کا سوال۔$sb$, $sb$سؤال ألا يزيغ القلوب بعد الهداية.$sb$),
  ($sb$rabbana_010$sb$, $sb$اقرار کہ اللہ تمام لوگوں کو بلا شک والے دن جمع کرے گا۔$sb$, $sb$إقرار بأن الله جامع الناس ليوم لا ريب فيه.$sb$),
  ($sb$rabbana_011$sb$, $sb$ہم ایمان لائے، ہمارے گناہ معاف کر اور جہنم سے بچا۔$sb$, $sb$آمنّا فاغفر لنا ذنوبنا وقنا عذاب النار.$sb$),
  ($sb$rabbana_012$sb$, $sb$ہم نے ایمان کی طرف بلانے والا سنا اور ایمان لائے۔$sb$, $sb$سمعنا داعي الإيمان فآمنّا.$sb$),
  ($sb$rabbana_013$sb$, $sb$اللہ سے وعدے کی تکمیل اور قیامت کے دن رسوائی نہ ہونے کا سوال۔$sb$, $sb$سؤال وعد الله وعدم الخزي يوم القيامة.$sb$),
  ($sb$rabbana_014$sb$, $sb$دعائے آدم — گناہ کا اقرار اور مغفرت کی درخواست۔$sb$, $sb$دعوة آدم — اعتراف بالذنب وطلب المغفرة.$sb$),
  ($sb$rabbana_015$sb$, $sb$ظالموں کے ساتھ نہ رکھے جانے کا سوال۔$sb$, $sb$سؤال ألا نكون مع القوم الظالمين.$sb$),
  ($sb$rabbana_016$sb$, $sb$اپنے اور پہلے ایمان لانے والوں کے لیے مغفرت — مومنوں سے بغض نہ ہو۔$sb$, $sb$المغفرة للنفس والسابقين — بلا غل تجاه المؤمنين.$sb$),
  ($sb$rabbana_017$sb$, $sb$تجھی پر بھروسہ، تیری ہی طرف رجوع اور تیری ہی طرف لوٹنا ہے۔$sb$, $sb$عليك توكلنا وإليك أنبنا وإليك المصير.$sb$),
  ($sb$rabbana_018$sb$, $sb$کافروں کے لیے آزمائش نہ بننے اور مغفرت کا سوال۔$sb$, $sb$سؤال ألا نكون فتنة للكافرين والمغفرة.$sb$),
  ($sb$rabbana_019$sb$, $sb$ہم ایمان لائے اور رسول کی پیروی کی — گواہوں میں لکھ لے۔$sb$, $sb$آمنّا واتّبعنا الرسول فاكتبنا مع الشاهدين.$sb$),
  ($sb$rabbana_020$sb$, $sb$اللہ کی حکمتِ تخلیق کا اقرار — جہنم سے پناہ۔$sb$, $sb$إقرار بحكمة الله في الخلق والاستعاذة من النار.$sb$),
  ($sb$rabbana_021$sb$, $sb$جسے تو نے جہنم میں ڈالا، اسے رسوا کیا۔$sb$, $sb$من تُدخل النار فقد أخزيته.$sb$),
  ($sb$rabbana_022$sb$, $sb$گناہ معاف کر، برائیاں مٹا اور نیکوں کے ساتھ اٹھا۔$sb$, $sb$اغفر ذنوبنا وكفّر سيئاتنا وتوفّنا مع الأبرار.$sb$),
  ($sb$rabbana_023$sb$, $sb$جو تو نے اپنے رسولوں کے ذریعے وعدہ کیا وہ عطا فرما۔$sb$, $sb$آتنا ما وعدتنا على رسلك.$sb$),
  ($sb$rabbana_024$sb$, $sb$اپنے، والدین اور تمام مومنوں کے لیے مغفرت کا سوال۔$sb$, $sb$سؤال المغفرة للنفس والوالدين وجميع المؤمنين.$sb$),
  ($sb$rabbana_025$sb$, $sb$بیویوں اور اولاد میں آنکھوں کی ٹھنڈک کا سوال۔$sb$, $sb$سؤال قرة العين من الأزواج والذرية.$sb$),
  ($sb$rabbana_026$sb$, $sb$اللہ سے جہنم کے عذاب کو دور کرنے کا سوال۔$sb$, $sb$سؤال الله صرف عذاب جهنم.$sb$),
  ($sb$rabbana_027$sb$, $sb$اللہ سے پل صراط پر ہمارے نور کی تکمیل اور مغفرت کا سوال۔$sb$, $sb$سؤال إتمام النور والمغفرة على الصراط.$sb$),
  ($sb$rabbana_028$sb$, $sb$اپنے اور پہلے ایمان لانے والوں کے لیے مغفرت۔$sb$, $sb$المغفرة للنفس والسابقين في الإيمان.$sb$),
  ($sb$rabbana_029$sb$, $sb$گناہوں اور زیادتی کی معافی — اور ثابت قدمی۔$sb$, $sb$المغفرة للذنوب والإسراف والتثبيت.$sb$),
  ($sb$rabbana_030$sb$, $sb$ابراہیم کی دعا — اپنے اور اولاد کے لیے قیامِ نماز۔$sb$, $sb$دعوة إبراهيم — إقامة الصلاة للنفس والذرية.$sb$),
  ($sb$rabbana_031$sb$, $sb$حساب کے دن اپنے، والدین اور مومنوں کے لیے مغفرت۔$sb$, $sb$المغفرة للنفس والوالدين والمؤمنين يوم الحساب.$sb$),
  ($sb$rabbana_032$sb$, $sb$ابراہیم کی حکمت اور نیکوں کی رفاقت کی دعا۔$sb$, $sb$دعوة إبراهيم — الحكم ومرافقة الصالحين.$sb$),
  ($sb$rabbana_033$sb$, $sb$بعد والوں میں باعزت یاد کیے جانے کا سوال۔$sb$, $sb$سؤال ذكر صدق في الآخرين.$sb$),
  ($sb$rabbana_034$sb$, $sb$اللہ سے جنت النعیم کا وارث بننے کا سوال۔$sb$, $sb$سؤال أن يكون من ورثة جنة النعيم.$sb$),
  ($sb$rabbana_035$sb$, $sb$ابراہیم کی اپنے باپ کے لیے دعا — منع ہونے سے پہلے۔$sb$, $sb$دعوة إبراهيم لأبيه قبل النهي.$sb$),
  ($sb$rabbana_036$sb$, $sb$قیامت کے دن مجھے رسوا نہ کر۔$sb$, $sb$لا تخزني يوم يبعثون.$sb$),
  ($sb$rabbana_037$sb$, $sb$مجھے اور میرے اہل کو ان کے کاموں سے بچا۔$sb$, $sb$نجّني وأهلي مما يعملون.$sb$),
  ($sb$rabbana_038$sb$, $sb$توبہ اور اللہ کی راہ پر چلنے والوں کے لیے فرشتوں کی دعا۔$sb$, $sb$دعاء الملائكة للتائبين المتبعين سبيله.$sb$),
  ($sb$rabbana_039$sb$, $sb$فرشتے مومنوں اور ان کے نیک اہل کو جنت میں داخلے کی دعا۔$sb$, $sb$دعاء الملائكة بإدخال المؤمنين وصالحي أهليهم الجنة.$sb$),
  ($sb$rabbana_040$sb$, $sb$جسے تو نے اس دن برائیوں سے بچایا، اس پر رحم فرمایا۔$sb$, $sb$من وقيته السيئات يومئذ فقد رحمته.$sb$),
  ($sb$ruquiya_001$sb$, $sb$سورۃ الفاتحہ — نبی ﷺ نے اسے دم کا ذریعہ قرار دیا۔$sb$, $sb$سورة الفاتحة — أقرّها النبي ﷺ رقية.$sb$),
  ($sb$ruquiya_002$sb$, $sb$آیت الکرسی — دن بھر شیطان سے حفاظت۔$sb$, $sb$آية الكرسي — حرز من الشيطان طوال اليوم.$sb$),
