  ($sb$sleeping_tasbih_1$sb$, $sb$سونے سے پہلے 33 بار — دن کے خادم سے بہتر۔$sb$, $sb$33 مرة قبل النوم — خير من خادم يعينه.$sb$),
  ($sb$sleeping_tasbih_2$sb$, $sb$سونے سے پہلے 33 بار — دن کے خادم سے بہتر۔$sb$, $sb$33 مرة قبل النوم — خير من خادم يعينه.$sb$),
  ($sb$sleeping_tasbih_3$sb$, $sb$سونے سے پہلے 34 بار — دن کے خادم سے بہتر۔$sb$, $sb$34 مرة قبل النوم — خير من خادم يعينه.$sb$),
  ($sb$sleeping_bismillah$sb$, $sb$لیٹتے وقت — رات کے لیے اپنے آپ کو اللہ کے سپرد کریں۔$sb$, $sb$تُقال عند الاضطجاع — استودع الله لليلة.$sb$),
